func truncate(s string, maxLen int) string {
	if len(s) <= maxLen {
		return s
	}
	return s[:maxLen]
}

// extractCheckpointID extracts the checkpoint ID from a commit message
func extractCheckpointID(t *testing.T, repo *repo, commitHash string) string {
	message, err := repo.getCommitMessage(commitHash)
	if err != nil {
		t.Logf("failed to get commit message: %v", err)
		return ""
	}

	// Look for Entire-Checkpoint trailer
	lines := strings.Split(message, "\n")
	for _, line := range lines {
		if strings.HasPrefix(line, "Entire-Checkpoint:") {
			parts := strings.Fields(line)
			if len(parts) >= 2 {
				return parts[1]
			}
		}
	}
	return ""
}

// Additional helper: runCommand executes a command in the repo's directory
func runCommand(t *testing.T, repo *repo, args ...string) string {
	cmd := repo.cli(args...)
	output, err := cmd.CombinedOutput()
	if err != nil {
		t.Logf("command failed (non-fatal for output capture): %v", err)
	}
	return string(output)
}

